  await browser.open(`${params.host_url}`)

  // Wait for host profile to load
  await browser.waitForSelector('h1, [data-testid=\'host-profile\'], .t1pxe1a4, [data-section-id=\'HOST_PROFILE\']', 15000)

  // Let page fully render
  await browser.wait(3000)

  // Scroll to load more content
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

  // Scroll to see listings
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

